def rollback_to_checkpoint(checkpoint_id):
    if checkpoint_id >= len(checkpoints):
        raise ValueError("Invalid checkpoint ID")
    target = checkpoints[checkpoint_id]

    # Restore state
    return client.messages.create(
        model="claude-sonnet-4-5-20250930",
        max_tokens=4096,
        tools=[{"type": "memory", "name": "task_state"}],
        messages=[{
            "role": "user",
            "content": f"Resume from checkpoint: {target['state']}"
        }]
    )

    # Rollback on failure detection
    if detect_failure(response):
        response = rollback_to_checkpoint(checkpoint_id - 1)

import json, gzip, time, hashlib
from typing import Any
import redis
import boto3

class TieredCheckpointStore:
    """Hot tier: Redis (< 1 hour old). Cold tier: S3 (archived)."""

    def __init__(self, redis_url: str, s3_bucket: str):
        self.redis = redis.from_url(redis_url)
        self.s3 = boto3.client('s3')
        self.bucket = s3_bucket
        self.hot_ttl = 3600  # 1 hour in seconds

    def _compress(self, data: dict) -> bytes:
        return gzip.compress(json.dumps(data).encode())

    def _decompress(self, blob: bytes) -> dict:
        return json.loads(gzip.decompress(blob))

    def save(self, session_id: str, checkpoint_id: str, state: dict) -> str:
        key = f"ckpt:{session_id}:{checkpoint_id}"
        payload = self._compress({
            'state': state,
            'saved_at': time.time(),
            'checksum': hashlib.sha256(json.dumps(state, sort_keys=True).encode()).hexdigest()
        })
        # Write to hot tier with TTL
        self.redis.setex(key, self.hot_ttl, payload)
        # Async write to cold tier (fire-and-forget in production)
        self.s3.put_object(Bucket=self.bucket, Key=key, Body=payload)
        return checkpoint_id

    def load(self, session_id: str, checkpoint_id: str) -> dict | None:
        key = f"ckpt:{session_id}:{checkpoint_id}"
        # Try hot tier first
        blob = self.redis.get(key)
        if blob is None:
            # Fallback to cold tier
            try:
                resp = self.s3.get_object(Bucket=self.bucket, Key=key)
                blob = resp['Body'].read()
                self.redis.setex(key, self.hot_ttl, blob)  # re-warm cache
            except self.s3.exceptions.NoSuchKey:
                return None
        return self._decompress(blob)['state']

import uuid
from enum import Enum

class RecoveryScope(Enum):
    STEP = 'step'
    TASK = 'task'
    PHASE = 'phase'

class PartialRecoveryEngine:
    def __init__(self, checkpoint_store):
        self.store = checkpoint_store
        self.rollback_count = 0
        self.MAX_ROLLBACKS = 5

    def recover(self, session_id: str, failure_context: dict,
                scope: RecoveryScope = RecoveryScope.TASK) -> dict:
        if self.rollback_count >= self.MAX_ROLLBACKS:
            raise RuntimeError(
                f"Max rollback depth {self.MAX_ROLLBACKS} reached. "
                "Escalating to human operator."
            )

        target_ckpt = self._find_rollback_target(session_id, failure_context, scope)
        if target_ckpt is None:
            raise ValueError(f"No valid checkpoint found for scope={scope.value}")

        state = self.store.load(session_id, target_ckpt)
        if state is None:
            raise ValueError(f"Checkpoint {target_ckpt} not found in store")

        self.rollback_count += 1
        failed_task_id = failure_context.get('task_id')

        # Remove failed task from completed set to allow re-execution
        if scope == RecoveryScope.STEP:
            state['completed_task_ids'].discard(failed_task_id)
        elif scope == RecoveryScope.TASK:
            # Re-queue the entire task
            state['pending_tasks'].insert(0, failure_context['task'])
            state['completed_task_ids'].discard(failed_task_id)

        return state

    def _find_rollback_target(self, session_id, failure_context, scope):
        # In production: query the checkpoint store for the latest checkpoint
        # whose phase_label < current failing phase
        return failure_context.get('last_good_checkpoint_id')
